import{_ as t,o as a,c as r,ag as i}from"./chunks/framework.Lq6hU67C.js";const u=JSON.parse('{"title":"Reading Live Leaks","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/reading-live-leaks.md","filePath":"how-to/reading-live-leaks.md"}'),o={name:"how-to/reading-live-leaks.md"};function l(s,e,n,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="reading-live-leaks" tabindex="-1">Reading Live Leaks <a class="header-anchor" href="#reading-live-leaks" aria-label="Permalink to &quot;Reading Live Leaks&quot;">​</a></h1><p>The <strong>Live Leaks</strong> tab is the primary MVP interface for inspecting handles that are still live at the current moment in Play Mode.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><ul><li><strong>List pane</strong> (left) — grouped entries sorted by severity, age, or occurrence count.</li><li><strong>Detail pane</strong> (right) — leak trace, severity badge, actions, optional stack trace.</li><li>Split width is resizable and persisted in EditorPrefs.</li></ul><h2 id="toolbar-controls" tabindex="-1">Toolbar controls <a class="header-anchor" href="#toolbar-controls" aria-label="Permalink to &quot;Toolbar controls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Recording / Paused</strong></td><td>Toggle event capture (triggers ILPP recompile)</td></tr><tr><td><strong>Verbose</strong></td><td>Capture stack traces at load/release (more overhead)</td></tr><tr><td><strong>Clear</strong></td><td>Reset event log and live registry</td></tr><tr><td><strong>Show ignored</strong></td><td>Include allowlisted patterns in the list</td></tr><tr><td><strong>Search</strong></td><td>Filter groups by asset key or call site</td></tr><tr><td><strong>Live counter</strong></td><td>Group count + worst severity indicator</td></tr></tbody></table><h2 id="list-columns-conceptual" tabindex="-1">List columns (conceptual) <a class="header-anchor" href="#list-columns-conceptual" aria-label="Permalink to &quot;List columns (conceptual)&quot;">​</a></h2><p>Each group shows:</p><ul><li>Asset or scene key (<code>DebugName</code> / resolved address)</li><li>Call site (<code>FileName:line</code> or member name)</li><li>Operation kind (LoadAsset, Instantiate, LoadScene, …)</li><li>Handle count when multiple live handles share the same site (<code>×N</code>)</li><li>Severity color dot</li></ul><h2 id="detail-panel" tabindex="-1">Detail panel <a class="header-anchor" href="#detail-panel" aria-label="Permalink to &quot;Detail panel&quot;">​</a></h2><ul><li><strong>Leak trace</strong> — chronological load origin and lifecycle hints.</li><li><strong>Severity badge</strong> — Normal, Aging, RedundantLoad, SceneSurvivor.</li><li><strong>Ignore this pattern</strong> — add call site to allowlist.</li><li><strong>Copy trace</strong> — clipboard export for bug reports.</li><li><strong>Related call sites</strong> — other live handles for the same asset.</li><li><strong>Stack trace</strong> (Verbose) — foldout with captured stack at injection time.</li></ul><h2 id="sort-modes" tabindex="-1">Sort modes <a class="header-anchor" href="#sort-modes" aria-label="Permalink to &quot;Sort modes&quot;">​</a></h2><ul><li><strong>Severity</strong> — SceneSurvivor first (default for triage).</li><li><strong>Age</strong> — oldest live handles first.</li><li><strong>Occurrence</strong> — highest duplicate count first.</li></ul><h2 id="settings-menu-⋮" tabindex="-1">Settings menu (⋮) <a class="header-anchor" href="#settings-menu-⋮" aria-label="Permalink to &quot;Settings menu (⋮)&quot;">​</a></h2><ul><li>ILPP diagnostics</li><li>Edit assembly exclude list</li><li>Manage ignored patterns (dedicated window)</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Grey/yellow entries may be intentional preloads — use allowlist rather than forcing release.</li><li>Red <strong>SceneSurvivor</strong> after scene change is the strongest signal of a missing Release before transition.</li><li>After fixing code, re-enter Play Mode for a clean session or use <strong>Clear</strong>.</li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../concepts/leak-definition-and-severity.html">Leak definition and severity</a></li><li><a href="./allowlist-and-persistent-handles.html">Allowlist and persistent handles</a></li></ul>',19)])])}const p=t(o,[["render",l]]);export{u as __pageData,p as default};
